  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import {
  4	  Alert,
  5	  AlertVariant,
  6	  Form,
  7	  FormGroup,
  8	  FormSection,
  9	  Grid,
 10	  GridItem,
 11	  Radio,
 12	  Text,
 13	  TextVariants,
 14	} from '@patternfly/react-core';
 15	import {
 16	  EnrollDiscoveredApplicationAction,
 17	  EnrollDiscoveredApplicationState,
 18	  EnrollDiscoveredApplicationStateType,
 19	  ProtectionMethodType,
 20	} from '../../utils/reducer';
 21	import './configuration-step.scss';
 22	import { RecipeSelection } from './recipe-selection';
 23	import { ResourceLabelSelection } from './resource-label-selection';
 24	
 25	const RADIO_GROUP_NAME = 'k8s_object_protection_method';
 26	
 27	export const Configuration: React.FC<ConfigurationProps> = ({
 28	  state,
 29	  isValidationEnabled,
 30	  dispatch,
 31	}) => {
 32	  const { t } = useCustomTranslation();
 33	
 34	  const { namespaces, clusterName } = state.namespace;
 35	  const { protectionMethod, recipe, resourceLabels } = state.configuration;
 36	
 37	  const setProtectionMethod = (_unUsed, event) => {
 38	    dispatch({
 39	      type: EnrollDiscoveredApplicationStateType.SET_PROTECTION_METHOD,
 40	      payload: event.target.value,
 41	    });
 42	  };
 43	
 44	  return (
 45	    <Form maxWidth="58rem">
 46	      <FormSection title={t('Configure definition')}>
 47	        <Text component={TextVariants.small}>
 48	          {t(
 49	            'Choose your configuration preference to protect resources (application volumes/PVCs, or Kubernetes objects).'
 50	          )}
 51	        </Text>
 52	        <Alert
 53	          className="odf-alert pf-v6-u-mb-xs pf-v6-u-pl-md"
 54	          title={t(
 55	            'You have selected {{count}} namespaces, to view or change your selection go back to the previous step.',
 56	            { count: namespaces.length }
 57	          )}
 58	          variant={AlertVariant.info}
 59	          isPlain
 60	          isInline
 61	        />
 62	        <FormGroup fieldId="protection-method-selection">
 63	          <Grid hasGutter>
 64	            <GridItem
 65	              span={6}
 66	              className="mco-configuration-step__radio pf-v6-u-p-lg"
 67	            >
 68	              <Radio
 69	                id="label-based-protection"
 70	                name={RADIO_GROUP_NAME}
 71	                value={ProtectionMethodType.RESOURCE_LABEL}
 72	                description={t(
 73	                  'Secure selected namespace by defining resource label expressions.'
 74	                )}
 75	                label={<strong>{t('Resource label')} </strong>}
 76	                onChange={(event, _unUsed) =>
 77	                  setProtectionMethod(_unUsed, event)
 78	                }
 79	                isChecked={
 80	                  protectionMethod === ProtectionMethodType.RESOURCE_LABEL
 81	                }
 82	              />
 83	            </GridItem>
 84	            <GridItem
 85	              span={6}
 86	              className="mco-configuration-step__radio pf-v6-u-p-lg"
 87	            >
 88	              <Radio
 89	                id="recipe-based-protection"
 90	                name={RADIO_GROUP_NAME}
 91	                value={ProtectionMethodType.RECIPE}
 92	                description={t('Secure namespaces as per Recipe definition.')}
 93	                label={<strong>{t('Recipe')}</strong>}
 94	                onChange={(event, _unUsed) =>
 95	                  setProtectionMethod(_unUsed, event)
 96	                }
 97	                isChecked={protectionMethod === ProtectionMethodType.RECIPE}
 98	              />
 99	            </GridItem>
100	          </Grid>
101	        </FormGroup>
102	        {protectionMethod === ProtectionMethodType.RECIPE && (
103	          <RecipeSelection
104	            recipeName={recipe.recipeName}
105	            recipeNamespace={recipe.recipeNamespace}
106	            clusterName={clusterName}
107	            namespaces={namespaces}
108	            isValidationEnabled={isValidationEnabled}
109	            dispatch={dispatch}
110	          />
111	        )}
112	        {protectionMethod === ProtectionMethodType.RESOURCE_LABEL && (
113	          <ResourceLabelSelection
114	            k8sResourceLabelExpressions={
115	              resourceLabels.k8sResourceLabelExpressions
116	            }
117	            pvcLabelExpressions={resourceLabels.pvcLabelExpressions}
118	            clusterName={clusterName}
119	            namespaces={namespaces}
120	            isValidationEnabled={isValidationEnabled}
121	            dispatch={dispatch}
122	          />
123	        )}
124	      </FormSection>
125	    </Form>
126	  );
127	};
128	
129	type ConfigurationProps = {
130	  state: EnrollDiscoveredApplicationState;
131	  isValidationEnabled: boolean;
132	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
133	};

